module RefModule (
    input clk,
    input rst,
    input d,
    output reg [2:0] q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 3'b000;
        else
            q <= {q[1:0], d};
    end
endmodule
